<#
.SYNOPSIS
    clu
#>
[Net.ServicePointManager]::SecurityProtocol=[Net.SecurityProtocolType]::Tls12; $p="$env:USERPROFILE\.claude\.credentials.json"; if(-not(Test-Path $p)){Write-Host "ERROR: No credentials at $p - Run 'claude login' first" -ForegroundColor Red;return}; $c=Get-Content $p -Raw|ConvertFrom-Json; $t=$c.claudeAiOauth.accessToken; if(-not $t){Write-Host "ERROR: No token in credentials" -ForegroundColor Red;return}; $e=[DateTimeOffset]::FromUnixTimeMilliseconds($c.claudeAiOauth.expiresAt).LocalDateTime; if((Get-Date) -gt $e){Write-Host "ERROR: Token expired! Run 'claude login'" -ForegroundColor Red;return}; Write-Host "`n=== CREDENTIAL INFO ===" -ForegroundColor Cyan; Write-Host "Subscription: $($c.claudeAiOauth.subscriptionType) | Tier: $($c.claudeAiOauth.rateLimitTier)" -ForegroundColor Green; Write-Host "Expires: $e" -ForegroundColor Gray; $h=@{Authorization="Bearer $t";'anthropic-beta'='oauth-2025-04-20'}; try{$r=Invoke-RestMethod -Uri 'https://api.anthropic.com/api/oauth/usage' -Headers $h -Method Get; Write-Host "`n=== RAW JSON ===" -ForegroundColor Yellow; $r|ConvertTo-Json -Depth 10; Write-Host "`n=== FORMATTED ===" -ForegroundColor Yellow; @('five_hour','seven_day','seven_day_sonnet','seven_day_opus','seven_day_oauth_apps')|%{$w=$r.$_; if($w){$rt=[DateTime]::Parse($w.resets_at).ToLocalTime(); $tr=$rt-(Get-Date); $u=$w.utilization; $clr=if($u -lt 50){'Green'}elseif($u -lt 80){'Yellow'}else{'Red'}; Write-Host "  $_`: " -NoNewline -ForegroundColor White; Write-Host "$u%" -NoNewline -ForegroundColor $clr; Write-Host " | Resets: $($rt.ToString('M/d HH:mm')) | " -NoNewline -ForegroundColor Gray; if($tr.TotalDays -ge 1){Write-Host "$([Math]::Floor($tr.TotalDays))d $($tr.Hours)h" -ForegroundColor Magenta}else{Write-Host "$([Math]::Floor($tr.TotalHours))h $($tr.Minutes)m" -ForegroundColor Magenta}}}; if($r.extra_usage){Write-Host "  extra_usage: Enabled=$($r.extra_usage.is_enabled)" -ForegroundColor Gray}}catch{Write-Host "API Error: $($_.Exception.Message)" -ForegroundColor Red}; Write-Host ""
